// Process base suggestions + generate expanded queries + call Google
// ALL IN ONE NODE to avoid race conditions
const seed = $node.Webhook.json.body.seed_keyword;
const discId = $node.Webhook.json.body.discovery_id;
const cbUrl = $node.Webhook.json.body.callback_url;

// Parse base suggestions
let baseSuggestions = [];
try {
  const raw = $input.first().json;
  if (raw.body) {
    const parsed = JSON.parse(raw.body);
    baseSuggestions = parsed[1] || [];
  } else if (Array.isArray(raw)) {
    baseSuggestions = raw[1] || [];
  }
} catch(e) {}

// Persian normalizer
const ZWNJ = '\u200C';
function norm(t) {
  return t.replace(/\u0643/g,'\u06A9').replace(/\u064A/g,'\u06CC')
          .replace(/[\u064B-\u065F]/g,'')
          .replace(new RegExp(ZWNJ+'{2,}','g'), ZWNJ)
          .replace(/\s+/g,' ').trim();
}

// Stop words
const stops = new Set(['و','در','به','از','که','این','را','با','است','آن','یک','برای','تا','ها','های','می','شود']);

// Score relevance
function score(kw) {
  const sw = seed.split(/[\s\u200C]+/).filter(w => !stops.has(w));
  const kws = kw.split(/[\s\u200C]+/).filter(w => !stops.has(w));
  let m = 0;
  sw.forEach(s => { if (kws.some(k => k.includes(s) || s.includes(k))) m++; });
  return Math.min(100, Math.round((sw.length ? m/sw.length : 0.5) * 100) + Math.min(20, kws.length * 5));
}

// Is question?
function isQ(t) {
  return t.includes('؟') || ['چیست','چگونه','چرا','کجا','آیا','کدام'].some(q => t.includes(q));
}

// Collect all keywords
const all = new Map();
function add(kw, src) {
  const n = norm(kw);
  if (n.length < 3) return;
  const key = n.toLowerCase().replace(/\u200C/g, ' ');
  if (key === seed.toLowerCase().replace(/\u200C/g, ' ')) return;
  if (!all.has(key)) {
    all.set(key, {keyword: n, source: src, relevance: score(n), is_question: isQ(n)});
  }
}

// Add base suggestions
baseSuggestions.forEach(k => add(k, 'suggest'));

// Build output
const ideas = Array.from(all.values()).sort((a,b) => b.relevance - a.relevance).slice(0, 200);

return [{json: {discovery_id: discId, callback_url: cbUrl, ideas}}];
